import React, { useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import ThemeToggle from './ThemeToggle';
import {
  Cpu,
  LayoutDashboard,
  TrendingUp,
  LogOut,
  ShieldCheck,
  Terminal,
  User,
  Menu,
  X,
} from 'lucide-react';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate         = useNavigate();
  const location         = useLocation();
  const [mobileOpen, setMobileOpen] = useState(false);

  /* Trigger theme context so CSS variables update on toggle */
  useTheme();

  const handleLogout = () => {
    logout();
    setMobileOpen(false);
    navigate('/login');
  };

  const isActive = (path) => location.pathname === path;

  /* ── Shared link style factory ── */
  const linkStyle = (active, accent = false) => ({
    textDecoration: 'none',
    fontWeight: 700,
    fontSize: '10px',
    padding: '0.45rem 0.9rem',
    borderRadius: '10px',
    display: 'flex',
    alignItems: 'center',
    gap: '6px',
    textTransform: 'uppercase',
    letterSpacing: '0.1em',
    whiteSpace: 'nowrap',
    transition: 'all 0.25s ease',
    cursor: 'pointer',
    ...(accent
      ? {
          backgroundImage: 'linear-gradient(135deg, var(--accent-secondary), var(--accent-primary))',
          color: '#ffffff',
          border: 'none',
          boxShadow: '0 0 12px var(--accent-glow)',
        }
      : active
      ? {
          backgroundColor: 'var(--accent-muted)',
          color: 'var(--accent-primary)',
          border: '1px solid var(--accent-primary)',
        }
      : {
          backgroundColor: 'transparent',
          color: 'var(--text-secondary)',
          border: '1px solid transparent',
        }),
  });

  const navLinks = user ? (
    <>
      <Link to="/dashboard" style={linkStyle(isActive('/dashboard'))} onClick={() => setMobileOpen(false)}>
        <LayoutDashboard size={13} /> Dashboard
      </Link>
      <Link to="/generate" style={linkStyle(isActive('/generate'))} onClick={() => setMobileOpen(false)}>
        <TrendingUp size={13} /> Strategy
      </Link>
      <Link to="/profile" style={linkStyle(isActive('/profile'))} onClick={() => setMobileOpen(false)}>
        <User size={13} /> Node
      </Link>
      <button
        onClick={handleLogout}
        title="Terminate Session"
        style={{
          backgroundColor: 'rgba(239, 68, 68, 0.08)',
          color: '#ef4444',
          border: '1px solid rgba(239, 68, 68, 0.2)',
          padding: '0.45rem 0.75rem',
          borderRadius: '10px',
          cursor: 'pointer',
          display: 'flex',
          alignItems: 'center',
          gap: '6px',
          fontSize: '10px',
          fontWeight: 700,
          textTransform: 'uppercase',
          letterSpacing: '0.1em',
          transition: 'all 0.25s ease',
          whiteSpace: 'nowrap',
        }}
        onMouseEnter={e => {
          e.currentTarget.style.backgroundColor = 'rgba(239, 68, 68, 0.18)';
          e.currentTarget.style.borderColor = 'rgba(239, 68, 68, 0.5)';
        }}
        onMouseLeave={e => {
          e.currentTarget.style.backgroundColor = 'rgba(239, 68, 68, 0.08)';
          e.currentTarget.style.borderColor = 'rgba(239, 68, 68, 0.2)';
        }}
      >
        <LogOut size={13} />
        <span className="hidden sm:inline">Logout</span>
      </button>
    </>
  ) : (
    <>
      <Link to="/login" style={linkStyle(isActive('/login'))} onClick={() => setMobileOpen(false)}>
        <Terminal size={13} /> Access
      </Link>
      <Link to="/register" style={linkStyle(false, true)} onClick={() => setMobileOpen(false)}>
        <ShieldCheck size={13} /> Initialize
      </Link>
    </>
  );

  return (
    <>
      {/* ── Sticky wrapper — sits above page content ── */}
      <div style={{
        position: 'sticky',
        top: 0,
        zIndex: 200,
        width: '100%',
        padding: '12px 16px 0',
        boxSizing: 'border-box',
        /* stops the sticky bar from catching background scroll */
        pointerEvents: 'none',
      }}>
        <nav style={{
          pointerEvents: 'auto',
          width: '100%',
          maxWidth: '1160px',
          margin: '0 auto',
          backgroundColor: 'var(--surface-glass)',
          backdropFilter: 'blur(20px)',
          WebkitBackdropFilter: 'blur(20px)',
          border: '1px solid var(--surface-border)',
          borderRadius: '18px',
          boxShadow: 'var(--shadow-elevated)',
          padding: '0.55rem 1.25rem',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          transition: 'background-color 0.3s ease, border-color 0.3s ease',
        }}>

          {/* Brand */}
          <Link
            to="/"
            style={{
              textDecoration: 'none',
              display: 'flex',
              alignItems: 'center',
              gap: '10px',
              color: 'var(--text-primary)',
              fontWeight: 800,
              fontSize: '0.85rem',
              letterSpacing: '0.18em',
              textTransform: 'uppercase',
              flexShrink: 0,
            }}
          >
            <div style={{
              width: '34px',
              height: '34px',
              borderRadius: '10px',
              background: 'var(--accent-muted)',
              border: '1px solid var(--accent-primary)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              boxShadow: '0 0 12px var(--accent-glow)',
              flexShrink: 0,
            }}>
              <Cpu size={16} color="var(--accent-primary)" />
            </div>
            <span style={{ display: 'none' }} className="sm-visible">Finify AI</span>
          </Link>

          {/* Desktop links */}
          <div style={{
            display: 'flex',
            alignItems: 'center',
            gap: '0.35rem',
          }}
            className="desktop-nav"
          >
            <ThemeToggle />
            {navLinks}
          </div>

          {/* Mobile hamburger */}
          <button
            onClick={() => setMobileOpen(v => !v)}
            aria-label="Toggle menu"
            className="mobile-menu-btn"
            style={{
              display: 'none',          /* shown via CSS below */
              background: 'none',
              border: '1px solid var(--surface-border)',
              borderRadius: '8px',
              padding: '0.4rem',
              cursor: 'pointer',
              color: 'var(--text-primary)',
              alignItems: 'center',
              justifyContent: 'center',
            }}
          >
            {mobileOpen ? <X size={18} /> : <Menu size={18} />}
          </button>
        </nav>

        {/* Mobile dropdown */}
        {mobileOpen && (
          <div
            className="mobile-dropdown"
            style={{
              width: '100%',
              maxWidth: '1160px',
              margin: '6px auto 0',
              backgroundColor: 'var(--surface-glass)',
              backdropFilter: 'blur(20px)',
              WebkitBackdropFilter: 'blur(20px)',
              border: '1px solid var(--surface-border)',
              borderRadius: '14px',
              boxShadow: 'var(--shadow-elevated)',
              padding: '0.75rem',
              display: 'flex',
              flexDirection: 'column',
              gap: '0.35rem',
              pointerEvents: 'auto',
            }}
          >
            <div style={{ marginBottom: '0.25rem' }}>
              <ThemeToggle />
            </div>
            {navLinks}
          </div>
        )}
      </div>

      {/* Responsive CSS injected once */}
      <style>{`
        @media (max-width: 640px) {
          .desktop-nav { display: none !important; }
          .mobile-menu-btn { display: flex !important; }
        }
        .sm-visible {
          display: inline !important;
        }
        @media (max-width: 400px) {
          .sm-visible { display: none !important; }
        }
      `}</style>
    </>
  );
};

export default Navbar;
